import React, { useState, useEffect } from "react";
import { Form, Button, Col, Row } from "react-bootstrap";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import Header from "../../components/Headers/Header";
import ReactQuill from "react-quill";
import "react-quill/dist/quill.snow.css";

const EditDrug = () => {
    const { id } = useParams();
    const navigate = useNavigate();

    const [drug, setDrug] = useState({
        medicine_code: "",
        medicine_name: "",
        medicine_type_name: "",
        price: "",
        unit: "",
        description: "",
    });

    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [isSubmitting, setIsSubmitting] = useState(false);

    // Fetch medicine data
    useEffect(() => {
        fetchMedicine();
    }, [id]);

    const fetchMedicine = async () => {
        try {
            const response = await axios.get(`http://localhost:5001/api/medicine/${id}`);
            console.log("Fetched drug data:", response.data);

            const medicineData = response.data;

            if (medicineData) {
                setDrug({
                    medicine_code: medicineData.medicine_code || "",
                    medicine_name: medicineData.medicine_name || "",
                    medicine_type_name: medicineData.MedicineType?.medicine_type_name || "",
                    price: medicineData.price ? medicineData.price.toString() : "",
                    unit: medicineData.unit || "",
                    description: medicineData.description || "",
                });
            }
        } catch (error) {
            console.error("Error fetching drug data:", error);
            setError("Could not find the drug or an error occurred while loading data.");
        } finally {
            setLoading(false);
        }
    };

    // Handle input change
    const handleChange = (e) => {
        const { name, value } = e.target;
        setDrug((prev) => ({ ...prev, [name]: value }));
    };

    // Handle description change (ReactQuill)
    const handleDescriptionChange = (value) => {
        setDrug((prev) => ({ ...prev, description: value }));
    };

    // Handle form submission
    const handleUpdate = async (e) => {
        e.preventDefault();

        if (!drug.medicine_code || !drug.medicine_name || !drug.medicine_type_name || !drug.price || !drug.unit || !drug.description) {
            alert("Please fill in all required fields!");
            return;
        }

        setIsSubmitting(true);
        try {
            const updateData = {
                medicine_code: drug.medicine_code,
                medicine_name: drug.medicine_name,
                medicine_type_name: drug.medicine_type_name,
                price: parseInt(drug.price),
                unit: drug.unit,
                description: drug.description,
            };

            console.log("Sending update data:", updateData);

            await axios.put(`http://localhost:5001/api/medicine/${id}`, updateData);

            alert("Update successful!");
            navigate("/drug");
        } catch (error) {
            console.error("Error updating drug:", error);
            alert(`Update failed! Error: ${error.response?.data?.message || error.message}`);
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleCancel = () => {
        navigate("/drug");
    };

    if (loading) return <p>Loading data...</p>;
    if (error) return <p style={{ color: "red" }}>{error}</p>;

    return (
        <>
            <Header />
            <div className="container mt-4">
                <h4 className="mb-4" style={{ fontSize: "28px", fontWeight: "bold" }}>Edit Drug</h4>
                <Form onSubmit={handleUpdate}>
                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="medicineCode">
                                <Form.Label>Medicine Code <span style={{ color: "red" }}>*</span></Form.Label>
                                <Form.Control
                                    type="text"
                                    placeholder="Medicine Code (e.g., MED002)"
                                    name="medicine_code"
                                    value={drug.medicine_code}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                        <Col md={6}>
                            <Form.Group controlId="medicineName">
                                <Form.Label>Medicine Name <span style={{ color: "red" }}>*</span></Form.Label>
                                <Form.Control
                                    type="text"
                                    placeholder="Medicine Name"
                                    name="medicine_name"
                                    value={drug.medicine_name}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                    </Row>

                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="medicineTypeName">
                                <Form.Label>Medicine Type <span style={{ color: "red" }}>*</span></Form.Label>
                                <Form.Control
                                    type="text"
                                    placeholder="Medicine Type (e.g., Antibiotic)"
                                    name="medicine_type_name"
                                    value={drug.medicine_type_name}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                        <Col md={6}>
                            <Form.Group controlId="drugPrice">
                                <Form.Label>Price (VND) <span style={{ color: "red" }}>*</span></Form.Label>
                                <Form.Control
                                    type="number"
                                    placeholder="Price (VND)"
                                    name="price"
                                    value={drug.price}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                    </Row>

                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="drugUnit">
                                <Form.Label>Unit <span style={{ color: "red" }}>*</span></Form.Label>
                                <Form.Control
                                    type="text"
                                    placeholder="Unit (e.g., tablet)"
                                    name="unit"
                                    value={drug.unit}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                    </Row>

                    <Form.Group controlId="drugDescription" className="mb-4">
                        <Form.Label>Description <span style={{ color: "red" }}>*</span></Form.Label>
                        <ReactQuill
                            theme="snow"
                            value={drug.description}
                            onChange={handleDescriptionChange}
                            placeholder="Enter description..."
                            style={{ height: "200px", marginBottom: "50px" }}
                        />
                    </Form.Group>

                    <div className="d-flex justify-content-end" style={{ marginTop: "50px" }}>
                        <Button variant="danger" onClick={handleCancel} className="me-2">Cancel</Button>
                        <Button
                            variant="primary"
                            type="submit"
                            disabled={isSubmitting}
                        >
                            {isSubmitting ? "Saving..." : "Save"}
                        </Button>
                    </div>
                </Form>
            </div>
        </>
    );
};

export default EditDrug;
